1	const countNeighbors = (cell: number[], livingCells: number[][]): number => {
2	  const [x, y] = cell;
3	  return livingCells.filter(
4	    ([cx, cy]) =>
5	      Math.abs(cx - x) <= 1 &&
6	      Math.abs(cy - y) <= 1 &&
7	      !(cx === x && cy === y)
8	  ).length;
9	};
10	
11	const isAlive = (cell: number[], livingCells: number[][]): boolean =>
12	  livingCells.some(([cx, cy]) => cx === cell[0] && cy === cell[1]);
13	
14	const neighborOffsets = [-1, 0, 1].flatMap((dx) =>
15	  [-1, 0, 1].map((dy) => [dx, dy])
16	).filter(([dx, dy]) => !(dx === 0 && dy === 0));
17	
18	const getDeadNeighbors = (livingCells: number[][]): number[][] => {
19	  const seen = new Set<string>();
20	  return livingCells.flatMap(([x, y]) =>
21	    neighborOffsets
22	      .map(([dx, dy]) => [x + dx, y + dy])
23	      .filter((cell) => {
24	        const key = cell.join(",");
25	        if (isAlive(cell, livingCells) || seen.has(key)) return false;
26	        seen.add(key);
27	        return true;
28	      })
29	  );
30	};
31	
32	export const nextGeneration = (livingCells: number[][]): number[][] => {
33	  const survivors = livingCells.filter((cell) => {
34	    const neighborCount = countNeighbors(cell, livingCells);
35	    return neighborCount === 2 || neighborCount === 3;
36	  });
37	
38	  const newborns = getDeadNeighbors(livingCells).filter(
39	    (cell) => countNeighbors(cell, livingCells) === 3
40	  );
41	
42	  return [...survivors, ...newborns].sort(([ax, ay], [bx, by]) =>
43	    ay !== by ? ay - by : ax - bx
44	  );
45	};
