1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty grid for empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should return empty grid for single live cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should return empty grid for two live cells (underpopulation)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a block of four cells alive (still life)", () => {
15	    expect(nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1]])).toEqual([[0, 0], [1, 0], [0, 1], [1, 1]]);
16	  });
17	  it("should transform a vertical blinker to a horizontal blinker", () => {
18	    expect(nextGeneration([[0, 0], [0, 1], [0, 2]])).toEqual([[-1, 1], [0, 1], [1, 1]]);
19	  });
20	  it("should revive a dead cell with exactly 3 live neighbors (reproduction)", () => {
21	    expect(nextGeneration([[0, 0], [1, 0], [0, 1]])).toEqual([[0, 0], [1, 0], [0, 1], [1, 1]]);
22	  });
23	  it("should kill a live cell with more than 3 live neighbors (overpopulation)", () => {
24	    // Center cell (1,1) has 4 live neighbors: (0,0),(1,0),(2,0),(0,1)
25	    // With 4 neighbors, (1,1) should die from overpopulation
26	    const result = nextGeneration([[0, 0], [1, 0], [2, 0], [0, 1], [1, 1]]);
27	    expect(result).not.toContain([1, 1]);
28	    expect(result.some(([x, y]) => x === 1 && y === 1)).toBe(false);
29	  });
30	});
